// Log unknown task size and prepare Discord alert payload
const task = $input.first().json;
const taskSize = task.Size || 'null/undefined';
const taskName = task.Name || task.name || task.properties?.Name?.title?.[0]?.plain_text || 'Unnamed Task';
const taskId = task.id || 'unknown-id';

return [{
  json: {
    taskSize: taskSize,
    taskName: taskName,
    taskId: taskId,
    originalTask: task,
    alertMessage: `⚠️ **Unknown Task Size**\n\nTask: ${taskName}\nSize: ${taskSize}\nID: ${taskId}\n\nManual review required.`,
    loggedAt: new Date().toISOString()
  }
}];

// Simplified Fastlane Validation (Schema v2)
// Only check: Pre-Approved = true
const task = $input.first().json;
const preApproved = task['Pre-Approved'] === true;

return [{
  json: {
    fastlaneValid: preApproved,
    failedChecks: preApproved ? [] : ['not_pre_approved'],
    taskId: task.id,
    taskName: task.Name || 'Unnamed',
    task: task
  }
}];

