// Create Complex Sub-Tasks (Schema v2)
const mainTask = $input.first().json;
const projectName = mainTask.Project || mainTask.projectName || 'Unknown Project';
const taskName = mainTask.properties?.Name?.title?.[0]?.plain_text || mainTask.Name || 'Unnamed Task';

const subTasks = [
  {
    name: `[${projectName}] Concept: ${taskName}`,
    phase: 'Concept',
    assignedTo: 'Product & Strategy',
    mainTaskId: mainTask.id,
