return subTasks.map(task => ({json: task}));

// Update Notion task status + call FlowClaw Executor (v1.0)
const items = $input.all();
const results = [];

for (const item of items) {
  const mainTaskId = item.json.mainTaskId || item.json.taskId;

  if (!mainTaskId) {
    results.push({json: {status: 'skipped', reason: 'no mainTaskId'}});
    continue;
  }

  try {
    const resp = await fetch('http://127.0.0.1:8765/workflow/execute', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({
        workflowName: 'fastlane-deploy',
        context: {
          taskId: mainTaskId,
          project_name: item.json.project || item.json.projectName || 'unknown',
          taskName: item.json.taskName || item.json.name || 'Fastlane Task',
          description: 'Auto-triggered by n8n v1.0'
        }
      })
    });

    const data = await resp.json();
    results.push({json: {
      status: data.status,
      run_id: data.run_id,
      mainTaskId: mainTaskId,
      taskName: item.json.taskName || item.json.name
    }});
  } catch (err) {
    results.push({json: {status: 'error', error: err.message, mainTaskId}});
  }
}

return results;

// Normalize data after Downgrade to Standard (v1.0)
const item = $input.first().json;

// Extract from Notion update response
const taskId = item.id;
const taskName = item.properties?.Name?.title?.[0]?.plain_text || 'Unnamed';
const project = item.properties?.Project?.select?.name || '';
const taskSize = 'Standard'; // After downgrade

// Return in Notion Trigger format expected by Create Standard Sub-Tasks
return [{
  json: {
    id: taskId,
    Name: taskName,
    Size: taskSize,
    Project: project,
    properties: {
      Name: { title: [{ plain_text: taskName }] },
      Project: { select: { name: project } },
      Size: { select: { name: taskSize } }
    }
  }
}];

// v1.0: Map task Size to correct workflow YAML name
// Fastlane → fastlane-deploy
// Standard → simple-task
// Complex  → complex-task
const item = $input.first().json;

const sizeMap = {
  'Fastlane': 'fastlane-deploy',
  'Standard': 'simple-task',
  'Complex': 'complex-task'
};

const size = item.taskSize || item.Size || 'Standard';
const workflowName = sizeMap[size] || 'simple-task';

return [{
  json: {
    ...item,
    workflowName: workflowName,
    _routedBy: 'Map Workflow Name v1.0'
  }
}];
